import{j as e,b as l,c as i,aa as a}from"./chunks/framework.Bxf40uRC.js";const k=JSON.parse('{"title":"Redis之内存回收","description":"","frontmatter":{},"headers":[],"relativePath":"Redis/Redis之内存回收.md","filePath":"Redis/Redis之内存回收.md","lastUpdated":null}'),t={name:"Redis/Redis之内存回收.md"},s=a('<h1 id="redis之内存回收" tabindex="-1">Redis之内存回收 <a class="header-anchor" href="#redis之内存回收" aria-label="Permalink to &quot;Redis之内存回收&quot;">​</a></h1><ul><li>Redis是如何知道一个key是否过期呢？</li><li>是不是TTL到期就自动删除了呢？</li></ul><h2 id="一、过期策略" tabindex="-1">一、过期策略 <a class="header-anchor" href="#一、过期策略" aria-label="Permalink to &quot;一、过期策略&quot;">​</a></h2><h3 id="db结构" tabindex="-1">DB结构 <a class="header-anchor" href="#db结构" aria-label="Permalink to &quot;DB结构&quot;">​</a></h3><p>Redis本身是一个典型的key-value内存存储数据库，因此所有的key，value都保存在之前的Dict结构中。不过在其database结构体中，有两个Dict：一个用来记录key-value；另一个用来记录key-TTL</p><p><img src="https://s2.loli.net/2023/12/23/k4H1qr7hL2jmgXP.png" alt="image-20231223150221511"></p><p><img src="https://s2.loli.net/2023/12/23/aVFMPTwmC5NcH4S.png" alt="image-20231223150355074"></p><h4 id="两个问题" tabindex="-1">两个问题 <a class="header-anchor" href="#两个问题" aria-label="Permalink to &quot;两个问题&quot;">​</a></h4><ol><li>Redis是如何知道一个key是否过期呢？ <ul><li>利用两个Dict分别记录key-value以及key-ttl对</li></ul></li><li>是不是TTL到期就立即删除了呢？ <ul><li>惰性删除</li><li>周期删除</li></ul></li></ol><h3 id="惰性删除" tabindex="-1">惰性删除 <a class="header-anchor" href="#惰性删除" aria-label="Permalink to &quot;惰性删除&quot;">​</a></h3><p>顾名思义并不是在TTL到期后就立即删除，而是在访问一个key的时候，检查该key的存活时间，如果已经过期才删除</p><p><img src="https://s2.loli.net/2023/12/23/tl7Ny6CR14dKDro.png" alt="image-20231223150959724"></p><h3 id="周期删除" tabindex="-1">周期删除 <a class="header-anchor" href="#周期删除" aria-label="Permalink to &quot;周期删除&quot;">​</a></h3><p>通过一个定时任务，周期性的<strong>抽样部分过期的key</strong>，然后执行删除。执行周期有两种:</p><ul><li>Redis会设置一个定时任务serverCron(),按照server.hz的频率来执行过期key清理，模式为SLOW；</li><li>Redis的每个事件循环前会调用beforeSleep()函数，执行过期key清理，模式为FAST</li></ul><p><img src="https://s2.loli.net/2023/12/23/2jbyxHptT5NR7oM.png" alt="image-20231223152013923"></p><h4 id="slow模式规则" tabindex="-1">SLOW模式规则 <a class="header-anchor" href="#slow模式规则" aria-label="Permalink to &quot;SLOW模式规则&quot;">​</a></h4><ul><li>执行频率受server.hz的影响，默认为10，即每秒执行10次，每个执行周期100ms</li><li>执行清理耗时不超过执行周期的25%</li><li>逐个遍历DB，逐个遍历db中的bucket，抽取20个key判断是否过期</li><li>如果没有达到时间上限(25ms) 并且过期key比例大于10% ，再进行一次抽样，否则结束</li></ul><h4 id="fast模式规则" tabindex="-1">FAST模式规则 <a class="header-anchor" href="#fast模式规则" aria-label="Permalink to &quot;FAST模式规则&quot;">​</a></h4><ul><li>执行频率受beforeSleep()调用频率影响，默认为10，每个执行周期100ms；</li><li>执行清理耗时不超过1ms；</li><li>逐个遍历DB，逐个遍历db中的bucket，抽取20个key判断是否过期；</li><li>如果没有达到时间上限(1ms) 并且过期key比例大于10% ，再进行一次抽样，否则结束；</li></ul><h2 id="二、淘汰策略" tabindex="-1">二、淘汰策略 <a class="header-anchor" href="#二、淘汰策略" aria-label="Permalink to &quot;二、淘汰策略&quot;">​</a></h2><p><strong>内存淘汰</strong>：就是当Redis内存使用达到阈值时，Redis主动挑选部分key删除以释放更多内存的流程。</p><p>Redis会在处理客户端命令的方法processCommand()中尝试做内存淘汰：</p><p><img src="https://s2.loli.net/2023/12/23/AvtfMwKNck7huFL.png" alt="image-20231223152816161"></p><p>Redis支持8种不同策略来选择要删除的key:</p><ol><li>noeviction: 不淘汰任何key，但是内存满时不允许写入新数据，默认就是这种策略。</li><li>volatile-ttl: 对设置了TTL的key，比较key的剩余TTL值，TTL越小越先被淘汰</li><li>allkeys-random: 对全体key ，随机进行淘汰。也就是直接从db-&gt;dict中随机挑选</li><li>volatile-random:对设置了TTL的key ，随机进行淘汰。也就是从db-&gt;expires中随机挑选</li><li>allkeys-lru:对全体key，基于LRU算法进行淘汰</li><li>volatile-lru:对设置了TTL的key，基于LRU算法进行淘汰</li><li>allkeys-lfu:对全体key，基于LFU算法进行淘汰</li><li>volatile-lfu: 对设置了TTL的key，基于LFU算法进行淘汰</li></ol><p>比较容易混淆的有两个:</p><ul><li>LRU(Least Recently Used)，最少最近使用。用当前时间减去最后一次访问时间，这个值越大则淘汰优先级越高；</li><li>LFU(Least Frequently Used)，最少频率使用。会统计每个key的访问频率，值越小淘汰优先级越高；</li></ul><p><img src="https://s2.loli.net/2023/12/23/gZasEy2QUmqoNjb.png" alt="image-20231223153329112"></p><p><img src="https://s2.loli.net/2023/12/23/n85D1eNGLZVcfEl.png" alt="image-20231223153828873"></p><p>LFU的访问次数之所以叫做逻辑访问次数，是因为并不是每次key被访问都计数，而是通过运算:</p><ol><li>生成 $0-1$之间的随机数R；</li><li>计算 $\\frac{1}{旧次数 * lfuLogFactor + 1}$, 记录为P，lfuLogFactor默认为10；</li><li>如果 $R &lt; P$ ，则计数器 + 1，且最大不超过255；</li><li>访问次数会随着时间衰减，距离上一次访问时间间隔lfuDecayTime分钟(默认1)，计数器-1；</li></ol><p><img src="https://s2.loli.net/2023/12/23/Fn2Zy8oQeujRLm3.png" alt="image-20231223154251368"></p><ul><li>NO_EVICTION：非驱逐方式；</li><li>maxmemory_samples：淘汰池子最大采样次数；</li></ul>',34),r=[s];function o(d,n,p,h,c,u){return l(),i("div",null,r)}const y=e(t,[["render",o]]);export{k as __pageData,y as default};
